def solve(a: str, b: str, c: str) -> str:
    def merge(x: str, y: str) -> str:
        if y in x:
            return x
        for i in range(min(len(x), len(y)), 0, -1):
            if x[-i:] == y[:i]:
                return x + y[i:]
        return x + y

    from itertools import permutations

    best = None
    for p in permutations([a, b, c]):
        res = merge(merge(p[0], p[1]), p[2])
        if best is None or len(res) < len(best) or (len(res) == len(best) and res < best):
            best = res
    return best
